-- Insert pre-extracted diet plan for user ecb89a15-98b8-4d12-9375-fb0aa3ce5792
UPDATE public.diet_plans SET is_active=false WHERE user_id='ecb89a15-98b8-4d12-9375-fb0aa3ce5792' AND is_active=true;
WITH new_plan AS (
  INSERT INTO public.diet_plans (user_id, title, objective, professional_name, kcal_target, start_date, is_active, general_guidelines, meal_options, document_id)
  VALUES ('ecb89a15-98b8-4d12-9375-fb0aa3ce5792', $lov$Schema Nutrizionale 1900$lov$, $lov$educazione alimentare, dimagrimento$lov$, $lov$Dott.ssa in Dietistica Fiamma Venturi$lov$, 1900, '2026-03-27'::date, true, $lov$[{"text": "Tutti i pesi sono a crudo e a netto degli scarti (se la pesatura deve avvenire ad alimento cotto è indicato).", "topic": "Pesi degli alimenti"}, {"text": "E' importante consumare il pasto in tranquillità masticando correttamente.", "topic": "Modalità di consumo del pasto"}, {"text": "Il consumo di acqua non deve essere inferiore a 1,5 l al giorno. L'assunzione di acqua deve essere distribuita nel corso della giornata. Soprattutto prima (nell'ora precedente l'attività deve essere consumato circa mezzo litro di acqua) e durante l' attività preferisci acque ricche di sali minerali, ossia con residuo fisso superiore a 200 mg/L : es. acquedotto/ acqua Lete/ San Gemini/Uliveto/Fabia ecc", "topic": "Consumo di acqua"}, {"text": "Il consumo di olio sia per condire che per cucinare, quindi indifferentemente cotto o crudo, è di circa 3 cucchiai al giorno. Un cucchiaio pesa circa 10 g , un cucchiaino circa 5. Evitare grassi quali burro, lardo, pancetta, panna, margarina idrogenata, maionese. Consiglio di usare uno spruzzino diffusore per olio, in modo da condire con moderazione ma in modo uniforme", "topic": "Consumo di olio"}, {"topic": "Consumo di alimenti di origine vegetale", "text": "Consuma sempre alimenti di origine vegetale (frutta, verdura e legumi), per migliorare sia il rapporto tra i macronutrienti, che l’assunzione di minerali, vitamine, e fibra alimentare."}, {"topic": "Prodotti integrali", "text": "Consuma prodotti preferibilmente integrali (es. più indicati il farro e l'orzo o la quinoa, il grano saraceno al posto di pasta e riso bianchi)."}, {"text": "la verdura deve essere preferibilmente di stagione (quantitativo medio a pasto circa 200 cotte o 250 g crude; insalate crude 80 g + 150 g verdura cruda es. lattuga 80 g + carote/ravanelli / pomodori ecc 150 g)", "topic": "Verdura"}, {"topic": "Carni e pesce", "text": "Preferire carni private del grasso visibile, pesce, pollame senza pelle."}, {"topic": "Consumo di pesce", "text": "Favorire il consumo di pesce soprattutto di mare e di taglia piccola. Limitare il consumo di pesce di taglia grande (es.: tonno e pesce spada). Preferire il tonno (fresco/surgelato o in scatola) striato , limitando il consumo della varietà di pinne gialle, ala lunga e obeso perché più ricche di mercurio."}, {"text": "I formaggi sia freschi che stagionati e i salumi sono una importante fonte di grassi, ne va ridotto il consumo come frequenza e porzione. Preferire latticini freschi come ricotta e fiocchi e salumi magri come bresaola crudo e cotto sgrassati e affettati di pollo o tacchino preferibilmente a basso contenuto di sodio.", "topic": "Formaggi e salumi"}, {"text": "un valido aiuto per mantenere bassi i livelli di colesterolo e un intestino sano è dato dal consumo dei legumi (al posto di altre proteine animali). In alternativa può essere un valido sostituto della pasta comune la pasta a base di farina di legumi (solito quantitativo) es. legumotti barilla", "topic": "Consumo di legumi"}, {"text": "Il consumo di dolci (creme/torte/pasticcini) , bibite zuccherate e di snack ipercalorici (patatine in busta) deve essere saltuario. Non più di 1 -2 volte a settimana. Il gelato artigianale è un dolce. E’ possibile preparare dolci limitando la quantità dello zucchero proposto in ricetta (dimezzandolo) . E’ possibile anche sostituire con sciroppo d’agave o di acero, che hanno un indice glicemico più basso dello zucchero ed un elevato potere dolcificante : a 100 g di zucchero corrispondono 75 g di sciroppo. Per gli snack salati è possibile sostituire con opzioni più salutari es. popcorn casalinghi (preparati in casa con i chicchi di mais)", "topic": "Dolci, bibite e snack"}, {"topic": "Consumo di alcolici", "text": "Il consumo di alcolici deve essere evitato nella quotidianità e limitato per frequenza e quantità alle sole occasioni sociali. Limitare il consumo di aperitivo a 1 volta a sett. preferendo birra piccola o 1 calice di vino o prosecco. Tra i cocktails analcolci preferire quelli secchi ad es. gin zero"}, {"text": "prima di svolgere attività fisica è importante idratarsi e portare la glicemia a valori adeguati nell'ora precedente all'attività consumare mezzo litro di acqua", "topic": "Indicazioni per attività fisica"}, {"text": "circa 45-30 min prima consumare a scelta : 40 g di albicocche disidratate (inoltre sono naturalmente ricche di potassio e magnesio) oppure frutta : banana/uva 150 g/ oppure altra frutta 200 g o 1 pacchettino di crackers o 40 g di pane o barretta energetica 30 g o 1 bicchiere di succo di frutta (da consumare in questo caso poco prima di iniziare l'attività)", "topic": "Spuntino pre-attività"}, {"text": "lo schema seguente è solo un aiuto organizzativo non deve essere vissuto rigidamente, colazione e spuntini può variarli a piacimento secondo le indicazioni generali del piano alimentare e pranzo e cena possono essere invertiti secondo necessità", "topic": "Organizzazione pasti"}, {"topic": "Consumo di frutta", "text": "la frutta può essere consumata nella giornata prima dopo o fuori dal pasto (max 350-400 g al giorno 3 frutti)"}]$lov$::jsonb, $lov${"sides": ["insalatona con feta 50 o scaglie di parmigiano 40 g + 40 g di olive verdi in salamoia + 2-3 cucchiai di mais + pane 70 g + frutta (la frutta può essere usata in alternativa per condire l'insalata, es fette di mela)", "frittata alta di verdura e patate con 2 uova, tagliata a cubetti, pane 70 g + frutta", "bresaola 70 g + scagliette di grana (max 20 g) + verdura + pane 70 g", "salmone affumicato preferibilmente scottato per ragioni igieniche 80 g + patate lesse 250 g + broccoli o altra verdura", "legumi cotti 100 g + tonno 40 g + verdura + pane 50 g + frutta di stagione", "legumi cotti 100 g + uovo sodo n. 1 + verdura + pane 50 g + frutta di stagione", "tonno sott'olio ben sgocciolato 80 g + patate lesse 250 g + fagiolini o altra verdura", "torta salata 200 g + frutta", "couscous o riso 80 g + pollo o legumi cotti 100 g + carote e zucchine o altra verdura", "piadina : piadina 80 g + 2-3 cucchiai di philadelphia light o protein o hummus di ceci + 40 g di affettato magro o 50 g di salmone affumicato + verdura a piacere", "wrap integrale (80 g circa) con hummus (2-3 cucchiai) o philadelphia protein (2-3 cucchiai) tacchino o salmone affumicato scottato 50 g e verdura (carote e cetrioli julienne)"], "second_courses_eggs_cheese": ["uova n. 2 (frittata/sode/crepes ecc)", "prodotto vegetariano tipo burger vegetale o di soja , o seitan o tofu ecc casalingo 150; confezionato 100 g", "legumi secchi 60 g (lenticchie o fagioli sia borlotti che cannellini o ceci) o 180 g di legumi freschi o già cotti, conditi secondo preferenza, con 1 cucchiaio di olio extravergine di oliva a testa.", "cecina 150 g", "tofu 150 g", "seitan/tempeh 120g", "soia secca 40-50 g", "burger veg 100-120 g (secondo confezione d'uso)", "affettato veg 80 g", "formaggio veg (es. cremoso di riso) 80 g", "formaggi (scamorza 80 g/ mozzarella-stracciatella 120 /primosale 100 g; parmigiano -emmenthal -pecorino 50 g/ stracchino 80 g/ feta o philadelphia 80 g/ ricotta 150 g/ fiocchi di latte 250 g)"], "breakfast_savory": ["pane integrale 30-40 g con 20 g di affettato magro (cotto/crudo sgrassati/bresaola) oppure 30 g di affettato di pollo o tacchino (puoi aggiungere verdura grigliata/insalata nel panino)", "pane integrale 30-40 g con 1 cucchiaio di ricotta o philadelphia light o greca + 30 g di salmone affumicato (puoi aggiungere verdura grigliata/insalata nel panino)", "pane integrale 50 g + 5 g di olio (1 cucchiaino o 2-3 spruzzate con spruzzino per olio) + pomodoro / origano se graditi", "pane integrale 30-40 g + formaggio 25 g", "pizza 60 g", "Pan bauletto integrale tostato 1 fetta + 1 uovo (puoi affrittellarlo in pentola antiaderente o farlo strapazzato o sodo) + sottiletta n.1", "Pan bauletto integrale tostato 1 fetta + Avocado 50 g + 1 uovo (puoi affrittellarlo in pentola antiaderente o farlo strapazzato o sodo)"], "recipes": [{"name": "Porridge", "steps": "Prima di tutto in un pentolino adagia la crusca d’avena, mescola con latte (o latte veg o acqua), sale, gira e poi poni sul fuoco, gira per 5 minuti, aggiungi a metà cottura il miele o il dolcificante scelto e assaggia. Valuta la consistenza, prosegui la cottura per una crema più compatta, o se è troppo denso aggiungi latte o acqua . Infine trasferiscilo nella ciotola e condiscilo come preferisci.", "ingredients": ["30 gr di fiocchi d'avena oppure fiocchi macinati o crusca d'avena", "circa 100 g di latte parz scremato, di soia oppure bevanda vegetale vegana a scelta ( oppure metà latte metà acqua per una versione più leggera)", "100 gr di frutta fresca di stagione (mirtilli, more, lamponi, banane, fragole, kiwi, mele, quello che preferisci, anche un mix di tutto) oppure 1 cucchiaino di miele oppure sciroppo d’acero oppure zucchero", "15 gr di frutta secca (a scelta 10 nocciole, 4 noci, 10 mandorle, 6 anacardi, 1 cucchiaio di arachidi, 1 cucchiaio di pistacchi oppure un mix di tutto) oppure 1 cucchiaino di semi oleosi (chia, sesamo, girasole o zucca ecc) oppure 15 gr di cioccolato", "un pizzico di sale"]}, {"ingredients": ["2 uova", "200 gr di farina", "25 gr di burro", "70 gr di zucchero", "200 ml di latte (anche veg se preferito)", "1 cucchiaio di succo di limone", "1 pizzico di sale", "1 cucchiaino di lievito per dolci", "125 gr di mirtilli"], "steps": "In una ciotola mescola la farina + lo zucchero + lievito, in un'altra ciotola a parte metti il latte con il succo di limone. In una ciotola monta le uova, poi aggiungi in maniera alternata il composto di farina ed il composto di latte. Infine aggiungi il burro fuso intiepidito e mescola fino ad ottenere una pastella liscia e omogenea. Copri il composto con della pellicola e lasciala riposare per 30 minuti. Riprendi l'impasto per pancakes ed aggiungi i mirtilli (tenerne qualcuno da parte per le decorazioni finali) Scalda una piccola padella antiaderente e ungila con un po' di burro e versa un mestolo di pastella al centro. Cuocere per 2 minuti, o fino a quando la pastella non inizierà a formare delle bollicine. Girare quindi i pancakes con una spatola e far cuocere anche dall'altro lato. Sono pronti e congelabili (da riporre con carta forno a dividerli perché non si attacchino)", "name": "Pancake ai mirtilli"}, {"name": "Insalata con pere, gorgonzola e noci", "steps": "Per ogni persona mischiare tutti gli ingredienti.", "ingredients": ["valeriana a piacere", "mezza pera Williams a fettine sottili", "50 gr. di gorgonzola dolce o piccante a cubetti", "4 gherigli di noce tritati", "sale", "pepe", "1 cucchiaio di olio extravergine di oliva"]}, {"ingredients": ["ceci cotti 150 g", "barbabietola a cubetti (1 media)", "feta a cubetti 30 g", "1 cucchiaio di succo di limone", "mezzo spicchio d’aglio", "prezzemolo", "sale", "pepe", "1 cucchiaio di olio"], "name": "Insalata con ceci, barbabietola e feta", "steps": "Per ogni persona mischiare tutti gli ingredienti."}, {"ingredients": ["50 gr. di formaggio caprino", "mezza mela verde a fettine sottili", "una decina di pinoli", "insalata a piacere", "aceto balsamico", "sale", "pepe", "1 cucchiaio di olio"], "steps": "Per ogni persona mischiare tutti gli ingredienti.", "name": "Insalata con mela, pinoli e caprino"}, {"name": "Insalata con salmone e arancia", "steps": "Per ogni persona mischiare tutti gli ingredienti.", "ingredients": ["valeriana a piacere", "70 gr. di salmone affumicato tagliato a striscioline", "gli spicchi di mezza arancia spellati a vivo", "poco sale", "aceto balsamico", "pepe rosa macinato o schiacciato", "1 cucchiaio di olio"]}, {"steps": "Per ogni persona mischiare tutti gli ingredienti.", "name": "Insalata con uova sode, acciughe e capperi", "ingredients": ["1 uovo sode tagliate a spicchi", "2 filetti di acciughe dissalate tagliati a piccoli pezzetti", "alcuni capperi sott’aceto", "insalata a piacere", "aceto", "sale", "un pizzico di origano", "1 cucchiaio di olio"]}, {"name": "Insalata con prosciutto affumicato e ananas", "steps": "Per ogni persona mischiare tutti gli ingredienti.", "ingredients": ["70 gr. di prosciutto di Praga tagliato in una unica fetta e ridotto a cubetti", "una fetta di ananas a dadini", "valeriana a piacere", "sale", "qualche goccia di senape", "1 cucchiaio di olio"]}, {"name": "Insalata con trippa, sedano e cetriolini", "steps": "Per ogni persona mischiare tutti gli ingredienti.", "ingredients": ["trippa lessata e tagliata a striscioline sottili", "sedano tagliato a rondelle", "insalata a piacere", "cetriolini sott’aceto", "sale", "pepe", "1 cucchiaio di olio"]}, {"ingredients": ["polpo lesso", "fagiolini", "zucchine", "patate", "sottaceti", "succo di limone", "prezzemolo tritato", "sale", "pepe", "maionese (1 cucchiaio raso va in sostituzione di 1 cucchiaio d’olio)"], "steps": "Per ogni persona mischiare: polpo lesso (si trova anche già cotto, nelle vaschette), fagiolini, zucchine, patate (che vanno al posto di una parte di pane previsto al pasto) bollite e sottaceti. Condire con una emulsione di succo di limone, prezzemolo tritato, sale, pepe e maionese.", "name": "Insalata con polpo e verdure bollite"}, {"steps": "Per ogni persona mischiare tutti gli ingredienti.", "name": "Insalata con fave, carciofi e pecorino fresco", "ingredients": ["fave fresche sgusciate a piacere", "carciofi crudi tagliati a fettine sottili", "70 gr. di pecorino fresco a dadini", "succo di limone", "foglioline di menta", "pepe", "sale", "1 cucchiaio di olio"]}, {"ingredients": ["fagioli borlotti o fagioli di Spagna o ceci già cotti 100 g", "1 cucchiaio di olio", "1 uovo sodo", "rucola", "cipollotto fresco se gradito", "sale", "pepe"], "name": "Insalata con legumi e uova", "steps": "Lessare le uova e farle raffreddare. In una ciotola unire i legumi e un cipollotto tritato a fettine sottilissime. Condire con sale, olio e pepe. Lasciar insaporire un’ora. Al momento di consumare l'insalatona, stendere la rucola su un piatto da portata, nel centro della quale andranno aggiunti i legumi. Disporre poi a raggiera le uova sode tagliate in quattro spicchi. Completare il tutto con un giro d’olio e una spolverata di sale e pepe."}, {"steps": "Per ogni persona lessare 2 uova, che una volta raffreddato sarà diviso in bianco e rosso e fatto a cubetti separatamente, 300 g di asparagi cotti al vapore per 5 minuti e poi spezzettati. Preparare una emulsione con 2 cucchiai di olio (1 solo se si cucina per se stessi e basta), limone 1 cucchiaino di capperi dissalati, poca erba cipollina tritata. Condire gli asparagi con questa emulsione in una ciotola, aggiungere da ultimo i cubetti di uova.", "name": "Insalata con asparagi e uova", "ingredients": ["2 uova", "300 g di asparagi", "2 cucchiai di olio", "limone", "1 cucchiaino di capperi dissalati", "poca erba cipollina tritata"]}], "second_courses_fish": ["pesce - acciughe, sardine, spigola,sogliola, orata, platessa ecc... 160 g circa, tonno, pesce spada in tranci 120g, polpo, seppie 250 g circa", "pesce conservato sgombro in scatola o tonno in salamoia 100 (il tonno non andrebbe consumato più di 2 volte al mese), sgombro , salmone affumicato, cotti o scottati tonno sott’olio 80 g"], "frequencies": ["Primo piatto come piatto unico (pasta integrale/riso/orzo/farro) con condimento vario 2-4 volte a settimana", "Carne 2-3 volte a settimana", "Pesce 2-3 volte a settimana", "legumi o prodotti vegetariani 2-3 volte a settimana", "Formaggi stagionati 1-2 volta a settimana", "affettati 0-1 volta a settimana", "uova n.2 1 volta a settimana", "pasto libero (es. pizza o cena etnica ecc) 1 volta a settimana"], "second_courses_meat": ["carne - pollo, tacchino, coniglio 150 g ; vitello magro o tagli magri di bovino 120 g circa", "1 scaloppina (alla pizzaiola; al limone) . Prodotto infarinato", "1 cotoletta (carne rossa o bianca sia fresca che prodotto surgelato) 100 g", "polpettone/involtini/spezzatino 120 g (peso cotto)", "roastbeef (peso cotto) 100 g", "simmenthal 120 g", "trippa 160 g + 10 g di parmigiano (grattugiato o scaglie)", "bresaola 70 g + parmigiano in scaglie 10- 20 g", "affettato magro (Crudo sgrassato /cotto sgrassato) 70 g", "fesa di pollo/tacchino a ridotto contenuto di sodio 80 g", "affettato medio grasso (cotto e crudo non sgrassati/speck) 60 g", "affettato grasso (salame/mortadella ecc) 50 g"], "cereal_equivalents": ["Pasta integrale, 100 g ; già cotto 200 g corrispondono a: Farro o Spelta, 100 g cotto 250 g, Orzo perlato, 100 g cotto 250 g, Pane integrale, 120 g, Pasta ,100 g cotto 200 g, Pane arabo, 120 g, Pane carasau, 90 g, Pane ai cereali, 120 g, Riso integrale, 100 g ; già cotta 200 g, Patate, 400 g, Risobasmati, 200 g cotto 230 g, quinoa, 100 g, cotto 270, pasta di sorgo, 100 g cotto 200, pasta di canapa, 100 g cotto 200, pasta di kamut , 100 g, cotto 200, pasta all'uovo secca 100, cotta 270, pasta ripiena fresca conservata (tipo i tortellini nel banco frigo) 120 g, gnocchi di patate/gnocchetti verdi 200 g, pasta fresca ripiena e non ripiena : 250 g, farina di mais (per fare la polenta) 100 g", "Pasta integrale, 80 g ; già cotto 160 g corrispondono a: Farro o Spelta, 80 g cotto 200 g, Orzo perlato, 80 g cotto 200 g, pasta fatta con farina di legumi, 80 g, grano saraceno 80 g cotto circa 200 g, quinoa, 80 g, cotto 200, sorgo, 80 g cotto 200, teff, 80 g cotto 200, amaranto, 70 g, cotto 200, couscous 80g, cotto 200 g, Pane integrale, 100 g, Pasta ,80 g cotto 160 g, Pane arabo, 100 g, Pane carasau, 80 g, Pane ai cereali, 100 g, Riso integrale, 80 g ; già cotta 160 g, Patate, 370 g, Risobasmati, 80 g cotto 190 g, pasta all'uovo secca 80, cotta 230, pasta ripiena fresca o cotta 230 g, gnocchi di patate 190 g, gnocchetti verdi preparato con spinaci 190 g, pasta all'uovo fresca conservata 100 g, polenta 150 g, farina di mais (per fare la polenta) 80 g, panzanella 200 g, ribollita 200 g, pappa al pomodoro 400 g, lasagne 150-180 g"], "first_courses": ["Pasta (o riso, farro, orzo, pasta di legumi, di mais, legumotti ecc) 100 g, con condimento prevalentemente vegetale (al pomodoro/agli zucchini/ alla zucca/ ai funghi/ 1 cucchiaio di pesto ecc)", "pasta al ragù: pasta 80 g + ragù di carne 40 g", "pasta al ragù: pasta 80 g + ragù veg (conta circa 40 g di soia secca a persona)", "pasta cacio e pepe : 80 g di pasta + 30-40 g di pecorino romano + pepe, 1-2 mestoli di acqua di cottura della pasta per mantecare bene", "farro/orzo/pasta 80 g + legumi cotti 80 g (peso secco 30 g)", "pasta/cous cous/risotto zucchini e gamberetti: pasta 80 g + gamberetti puliti 120 g (o misto mare 100 g) + zucchine", "pasta al salmone : pasta 80 g + salmone 40 g", "pasta al tonno : pasta 80 g + tonno 40 g + pomodoro", "pasta al pomodoro e vongole : pasta 80 g + vongole sgusciate 100 g + pomodoro", "pasta/farro al philadelphia zucchine e menta/basilico : pasta 80 g + philadelphia HD 30 g + zucchine (o altra verdura)", "cous cous (o riso basmati) 80 g + 80 g di pollo/tacchino + spezie se gradite (es. curry)", "pasta/orzo 80 g + ricotta 70 g + verdure (es. zucchine e menta/pomodorini ecc)", "lasagne/pasta la forno 200 g", "riso freddo 200 g", "torta salata 200 g", "gnocchi 180 g + salmone affumicato 50 g", "tortellini 100 g + 1 cucchiaio di panna veg + prosciutto cotto 20 g + 1 cucchiaio raso di parmigiano", "gnocchetti verdi 180 g + burro 15 g (1,5 cucchiai) + 2 cucchiai di parmigiano grattugiato (20 g circa)", "gnocchi al pomodoro e basilico : gnocchi 200 g + pomodoro e basilico + 1 cucchiaio di parmigiano", "farina di mais per polenta 80 g + baccalà 100 g *Peso cotto polenta 350 g*", "farina di mais per polenta 80 g + formaggio stagionato 30-40 g Peso cotto polenta 350 g"], "breakfast_sweet": ["latte ps 150 g o yogurt bianco 125 g o greco magro 150 g oppure kefir 150 g oppure skyr 150 g + biscotti frollini 35 g circa", "latte ps 150 g o yogurt bianco 125 g o greco magro 150 g oppure kefir 150 g oppure skyr 150 g + pezzo dolce vuoto 30-40 g ( plumcake/ kinder brioche/ camilla/ cornetto vuoto ecc)", "latte ps 150 g o yogurt bianco 125 g o greco magro 150 g oppure kefir 150 g oppure skyr o quark 150 g + 30 g di cereali + frutta 100-150 g", "latte ps 150 g o yogurt bianco 125 g o greco magro 150 g oppure kefir 150 g oppure skyr 150 g + cereali/muesli 30 g + frutta disidratata (albicocche/prugne/ datteri) 20 g", "pancakes/crepes 50 g circa /se il pancake contiene frutta es. mirtilli, fette di mela o banana il peso va a 80 g) + 1 cucchiaino di marmellata o miele o sciroppo di acero o agave o 1 cucchiaino di cacao spalmabile", "yogurt greco magro 170 g + 2 cucchiaini colmi di semi di chia (circa 15 g totali) + 1 cucchiaino di cacao amaro o 1 cucchiaio raso di burro di arachidi in polvere o 15 g di frutta secca + 1 cucchiaino di miele o crema di datteri o frutta disidratata 15 g, ossia due pezzi es. prugne o albicocche o due cucchiaini di uvetta o mirtilli disidratati (conviene mettere i semi di chia in acqua la sera prima lasciando riposare in frigo, se usi frutta disidratata pupi mettere anche quelli)", "torta casalinga senza creme 50 g (se la torta è di frutta, es. torta di mele, il peso va a 80 g)", "latte ps 150 g + 2 fette di pan bauletto (o 40 g di pane) con 1 cucchiaio di marmellata o di cacao spalmabile o burro di mandorle o arachidi", "porridge (30 g di riso/fiocchi di avena/ amaranto ecc + latte 100 ml + frutta fresca 150 g o 1 cucchiaio di miele o marmellata o 20 g di frutta disidratata + 10 g di frutta secca o 1 cucchiaio di granola)", "mix yogurt e cereali già confezionato (es. activia mix&go/ soyasun cereal/ muller mix )", "pane integrale 40 g + crema proteica (puoi prepararla da te con 30 g di whey protein (più adatte se dopo colazione fai attività fisica) o caseine (per prolungare il senso di sazietà) lavorate con uguale quantità di acqua o latte, si forma una crema spalmabile) + frutta 100 g o 1 cucchiaino di mi